/* apps/showcase/views/weather-radar/manifest.ts
 *
 * CROSS-DOMAIN view (ENC-538 / T4.6) — "weather radar / NEXRAD".
 *
 * A STATIC computed view that exercises the ViewTexture ESCAPE HATCH (ENC-532):
 * a 2D intensity field rendered as a heatmap via the `texturedQuad@1` pipeline.
 *
 * The 16x16 scalar field is read from the synthetic dataset
 * (apps/showcase/data/synthetic/heatmap.json, a 16x16 field over 200 frames; we
 * pick the representative t=0 frame, which spans the full [0,1] range) and
 * RASTERIZED at manifest-build time into an upscaled 192x192 RGBA8 colormap
 * using a NEXRAD-style radar palette (dark -> green -> yellow -> orange -> red ->
 * magenta), bilinearly interpolated for a smooth radar look. Those RGBA8 bytes
 * are base64'd into `manifest.textures` and applied via EngineHost.setTexturePixels;
 * the manifest's texturedQuad drawItem references the texture by id
 * (setDrawItemTexture). Purity preserved: the engine only BLITS the producer-
 * rasterized colormap onto a quad — it computes no per-pixel color from JSON.
 *
 * The cross-domain point: a weather-radar sweep is a colormapped scalar field —
 * the same texturedQuad path a market heatmap/spectrogram would use, pointed at a
 * meteorology domain.
 */

import type { SceneManifest } from '../../src/scene/commands';

// --- structural IDs (local to this view; scene is reset between views) ---
const PANE = 100;
const LAYER = 101;
const QUAD_BUFFER = 500;
const QUAD_GEOMETRY = 200;
const QUAD_DRAWITEM = 300;
const RADAR_TEXTURE = 700; // logical textureId referenced by setDrawItemTexture

// texturedQuad@1 instance record (Pos2Uv4 = x0, y0, x1, y1 rect in clip space).
// One instance; the pipeline generates the quad's 6 verts and maps uv 0..1 over
// the texture. Authored in clip space, so no transform is attached.
const QUAD: number[] = [-0.85, -0.85, 0.85, 0.85];

// 192x192 RGBA8 radar colormap, base64-encoded (NEXRAD palette over the
// bilinearly-upscaled t=0 frame of heatmap.json). width*height*4 bytes.
const RADAR_PIXELS_B64 =
  '';

export const manifest: SceneManifest = {
  label: 'Weather radar — intensity field',
  commands: [
    { cmd: 'createPane', id: PANE },
    { cmd: 'setPaneRegion', id: PANE, clipXMin: -0.97, clipXMax: 0.97, clipYMin: -0.97, clipYMax: 0.97 },
    { cmd: 'setPaneClearColor', id: PANE, r: 0.03, g: 0.04, b: 0.06, a: 1 },
    { cmd: 'createLayer', id: LAYER, paneId: PANE },

    { cmd: 'createBuffer', id: QUAD_BUFFER, byteLength: 0 },
    {
      cmd: 'createGeometry',
      id: QUAD_GEOMETRY,
      vertexBufferId: QUAD_BUFFER,
      format: 'pos2_uv4',
      vertexCount: 1,
    },

    { cmd: 'createDrawItem', id: QUAD_DRAWITEM, layerId: LAYER },
    { cmd: 'bindDrawItem', drawItemId: QUAD_DRAWITEM, pipeline: 'texturedQuad@1', geometryId: QUAD_GEOMETRY },
    // texturedQuad modulates the sampled texel by the draw-item color; white = pass-through.
    { cmd: 'setDrawItemColor', drawItemId: QUAD_DRAWITEM, r: 1, g: 1, b: 1, a: 1 },
    // Bind the producer-rasterized colormap (applied via setTexturePixels below).
    { cmd: 'setDrawItemTexture', drawItemId: QUAD_DRAWITEM, textureId: RADAR_TEXTURE },
  ],
  // The ViewTexture escape hatch: RGBA8 colormap uploaded via setTexturePixels
  // before the frame, so the texturedQuad drawItem finds its pixels at render time.
  textures: [
    {
      textureId: RADAR_TEXTURE,
      width: 192,
      height: 192,
      pixelsB64: RADAR_PIXELS_B64,
      format: 1, // RGBA8
    },
  ],
  // STATIC: the single quad instance is baked once (no live replay).
  uploads: [{ bufferId: QUAD_BUFFER, floats: QUAD }],
};
